import { useState, useEffect } from 'react';

export const useConversation = () => {
  const [messages, setMessages] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({});
  const [currentStep, setCurrentStep] = useState({ type: 'text' });

  // THE MASTER LIST: Derived directly from your PDF content
  const PROTOCOL_FIELDS = [
    // 1. SOCIO-DEMOGRAPHIC
    { field: "name", label: "Patient's Name", type: "text" },
    { field: "gender", label: "Gender", type: "choice", options: ["Male", "Female", "Transgender"] },
    { field: "dob", label: "Date of Birth", type: "text" },
    { field: "age", label: "Age", type: "text" },
    { field: "edu_qual", label: "Educational Qualification", type: "text" },
    { field: "marital_status", label: "Marital Status", type: "choice", options: ["Single", "Married", "Divorced", "Widowed", "Separated"] },
    { field: "occupation", label: "Occupation", type: "text" },
    { field: "ses", label: "Socio-Economic Status", type: "text" },
    { field: "religion", label: "Religion", type: "text" },
    { field: "residence", label: "Residence", type: "choice", options: ["Urban", "Rural", "Semi-urban"] },
    
    // 2. CHIEF COMPLAINTS
    { field: "complaints_chrono", label: "Chief Complaints (Chronological Order)", type: "text" },
    { field: "patient_verbatim", label: "Patient's Verbatim Statement", type: "text" },
    { field: "course", label: "Course of Illness", type: "choice", options: ["Continuous", "Episodic", "Deteriorating", "Progressing", "Improving", "Static"] },
    { field: "onset", label: "Mode of Onset", type: "choice", options: ["Sudden", "Immediate", "Abrupt", "Acute", "Subacute", "Gradual"] },
    { field: "precipitating", label: "Precipitating Factors", type: "text" },
    
    // 3. BIOLOGICALS
    { field: "sleep", label: "Sleep Pattern", type: "choice", options: ["Normal", "Insomnia", "Hypersomnia", "Disturbed"] },
    { field: "appetite", label: "Appetite", type: "choice", options: ["Normal", "Increased", "Decreased"] },
    
    // 4. PRE-MORBID PERSONALITY
    { field: "attitude_self", label: "Attitude towards self", type: "text" },
    { field: "mood_baseline", label: "Baseline Mood", type: "text" }
  ];

  const systemInstructions = `
    You are a NIMHANS Data Entry Slave.
    ONLY phrase the question for the provided field. 
    Refer to the person as "the patient". 
    Output ONLY valid JSON. No conversational filler.
    Format: {"message": "string"}
  `;

  const getNextField = (data) => PROTOCOL_FIELDS.find(f => !data[f.field]);

  useEffect(() => {
    const init = async () => {
      setIsTyping(true);
      const first = PROTOCOL_FIELDS[0];
      const res = await callOllama(`Ask for ${first.label}`, first);
      try {
        const parsed = JSON.parse(res);
        setMessages([{ sender: 'bot', text: parsed.message }]);
        setCurrentStep({ ...first, ...parsed });
      } catch (e) {
        setMessages([{ sender: 'bot', text: `Please provide the ${first.label}.` }]);
        setCurrentStep(first);
      }
      setIsTyping(false);
    };
    init();
  }, []);

  const callOllama = async (prompt, targetField) => {
    try {
      const response = await fetch("http://localhost:11434/api/generate", {
        method: "POST",
        body: JSON.stringify({
          model: "mistral",
          prompt: `SYSTEM: ${systemInstructions}\nFIELD: ${JSON.stringify(targetField)}\nCONTEXT: ${prompt}`,
          stream: false,
          format: "json"
        }),
      });
      const data = await response.json();
      return data.response;
    } catch (error) {
      return JSON.stringify({ message: "Ollama Connection Error." });
    }
  };

  const handleUserAnswer = async (answer) => {
    const updatedData = { ...userData, [currentStep.field]: answer };
    setUserData(updatedData);
    setMessages(prev => [...prev, { sender: 'user', text: answer }]);
    setIsTyping(true);

    const nextField = getNextField(updatedData);

    if (!nextField) {
      setMessages(prev => [...prev, { sender: 'bot', text: "NIMHANS Proforma Complete. Thank you." }]);
      setIsTyping(false);
      return;
    }

    const res = await callOllama(`Previous data: ${JSON.stringify(updatedData)}. Ask for ${nextField.label}.`, nextField);
    
    try {
      const parsed = JSON.parse(res);
      setMessages(prev => [...prev, { sender: 'bot', text: parsed.message }]);
      setCurrentStep({ ...nextField, ...parsed });
    } catch (e) {
      setMessages(prev => [...prev, { sender: 'bot', text: `What is the ${nextField.label}?` }]);
      setCurrentStep(nextField);
    }
    
    setIsTyping(false);
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
